  import java.util.Collections;
 
  import org.apache.log4j.Logger;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Application;
  import sailpoint.tools.Message;
  import sailpoint.object.ManagedAttribute;

  import java.io.FileInputStream;
  import java.io.FileNotFoundException;
  import java.io.IOException;

  import java.util.Scanner;
  import sailpoint.object.TaskResult; 
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Ascension-Rule-Remove-ManagedAttribute");

  logger.debug("Ascension-Rule-Remove-ManagedAttribute");
  public List delimToList(String delimiter,String lineString){
    List result = new ArrayList();
    if(Util.isNotNullOrEmpty(lineString) && !lineString.isEmpty()){
      if(Util.isNotNullOrEmpty(delimiter) && delimiter.equals(",")){
        List tempList = Util.csvToList(lineString);
        for(String str : tempList){
          if(Util.isNullOrEmpty(str)){
            str = "";
          }
          result.add(str.trim());
        }
      }else{
        String []str = lineString.split(delimiter);
        for(String s : str){
          if(Util.isNullOrEmpty(s)){
            s = "";
          }
          result.add(s.trim());
        }
      }
    }
    return result;
  }

  public void  removeManagedAttribute()throws Exception{
    logger.debug("Entering removeManagedAttribute");
    boolean isHeader = true;
    String lineString ="";
    FileInputStream inputFile = null;
    Scanner scanner = null;
    List headerList = new ArrayList();
    List dataList = new ArrayList();
    QueryOptions qo = null;
    Iterator iter = null;
    List<ManagedAttribute> resultList = null;


    try {
      inputFile = new FileInputStream(inputFileName);
      scanner = new Scanner(inputFile); 

      while (scanner.hasNextLine()) {
        lineString = scanner.nextLine();
        if (Util.isNotNullOrEmpty(lineString) && !lineString.isEmpty()) {
          if (isHeader) {
            isHeader = false;
            headerList = delimToList(delimiter, lineString);
            continue;
          }
          totalCount++;
          //# type, application, attribute, value
          dataList = delimToList(delimiter, lineString);
          if (headerList != null && !headerList.isEmpty() && dataList != null && dataList.size() > 3) {
            qo = new QueryOptions();
            qo.add(Filter.eq("application.name", dataList.get(1)));
            qo.add(Filter.eq("attribute", dataList.get(2)));
            qo.add(Filter.eq("value", dataList.get(3))); 

            resultList = context.getObjects(ManagedAttribute.class, qo);
            
            if(resultList!=null && !resultList.isEmpty()){
              successStr = successStr+(resultList.get(0).toXml())+NEWLINE;
              context.removeObject(resultList.get(0));
              successCount++;
            }else{
              failStr = failStr+lineString+NEWLINE;
              failCount++;
            }

          }else{
            failStr = failStr+lineString+NEWLINE;
            failCount++;
          }
          if(successCount>0){
            context.commitTransaction();
          }
        }
      }
    } catch (FileNotFoundException e) {
      logger.error("Exception in reading input file "+e.getMessage());
	  taskResult.addMessage(Message.error("Input file not found : "+e.getMessage(),null));
      taskResult.setCompletionStatus(TaskResult.CompletionStatus.Error);
    }catch (IOException e) {
      logger.error("Exception in reading input file "+e.getMessage());
	  taskResult.addMessage(Message.error("Exception in reading input file : "+e.getMessage(),null));
      taskResult.setCompletionStatus(TaskResult.CompletionStatus.Error);
    }finally{
      if(scanner!=null){
        scanner.close();
      }
      if(inputFile!=null){
        try {
          inputFile.close();
        } catch (IOException e) {
          logger.error("Exception in "+e.getMessage());
        }
      }
    }
    logger.debug("Exiting removeManagedAttribute");

  }


  logger.debug("Ascension-Rule-Remove-ManagedAttribute Starting");
  List successList = new ArrayList();
  String successStr ="";
  String failStr ="";
  int successCount = 0;
  int failCount =  0;
  int totalCount = 0;
  String inputFileName = "";

  String NEWLINE = System.getProperty("line.separator");
  String delimiter = ",";


  if(config!=null){
    inputFileName = config.get("inputFileName");
  }

  if(Util.isNotNullOrEmpty(inputFileName) ){
    removeManagedAttribute();
  }else{
    taskResult.addMessage(Message.warn("Task Input details are missing. Verify Task inputs."));
  }
  
  taskResult.addMessage(Message.info("Total Count : "+totalCount,null));
  taskResult.addMessage(Message.info("Success Count : "+successCount,null));
  if(failCount>0){
		taskResult.addMessage(Message.warn("Fail Count : "+failCount,null));
		taskResult.addMessage(Message.warn("Fail Details : "+failStr,null));
  }else{
		taskResult.addMessage(Message.info("Fail Count : "+failCount,null));
		taskResult.addMessage(Message.info("Fail Details : "+failStr,null));
  }
  taskResult.addMessage(Message.info("Success Details : "+successStr,null));


  logger.debug("Ascension-Rule-Remove-ManagedAttribute Ending");
  return "Total Count: " + totalCount + ", Success Count: " + successCount + ", Fail Count: " + failCount;
